                        onClick={handleExport}
                        className="flex-1 lg:flex-none flex items-center justify-center gap-3 px-8 py-4 bg-emerald-500 text-white rounded-[1.5rem] font-black shadow-xl shadow-emerald-500/20 hover:bg-emerald-600 hover:-translate-y-1 transition-all active:scale-95"
                      >
                        <FileSpreadsheet size={20} /> Xuất Excel
                      </button>
                    </div>
                  </div>
                  <DataTable data={extractedData} theme={currentTheme} />
                </div>
              )}
            </div>
          </div>
        </div>
      </main>

      {/* Printable Area - Only visible when printing */}
      <div className="hidden print:block p-10 bg-white min-h-screen">
        <h1 className="text-2xl font-bold text-center mb-8 uppercase">Mục lục văn bản hồ sơ</h1>
        <DataTable data={extractedData} theme={currentTheme} />
      </div>

      <div className={`fixed inset-y-0 right-0 w-80 bg-white/95 backdrop-blur-2xl shadow-2xl z-[55] transform transition-transform duration-500 ease-out border-l border-slate-100 no-print ${showConfigPanel ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="h-full flex flex-col p-8">
          <div className="flex items-center justify-between mb-10">
            <div className="flex items-center gap-3">
              <div className={`p-2 bg-${p}-100 text-${p}-600 rounded-xl`}>
                <Palette size={20} />
              </div>
              <h4 className="text-xl font-black text-slate-900 tracking-tight">Giao diện</h4>
            </div>
            <button onClick={() => setShowConfigPanel(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} /></button>
          </div>

          <div className="flex-1 space-y-10 overflow-y-auto pr-2 custom-scrollbar">
            <section>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-5">Chủ đề màu sắc</p>
              <div className="grid grid-cols-5 gap-3">
                {THEMES.map(t => (
                  <button key={t.id} onClick={() => setCurrentTheme(t)} className={`aspect-square rounded-2xl border-2 transition-all ${currentTheme.id === t.id ? 'border-slate-900 ring-4 ring-slate-100' : 'border-transparent shadow-sm'}`} style={{ backgroundColor: t.primary === 'blue' ? '#3B82F6' : t.primary === 'emerald' ? '#10B981' : t.primary === 'violet' ? '#8B5CF6' : t.primary === 'rose' ? '#F43F5E' : '#F59E0B' }} />
                ))}
              </div>
            </section>
          </div>
        </div>
      </div>

      {showHistory && (
        <div className="fixed inset-0 z-[60] flex justify-end no-print">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" onClick={() => setShowHistory(false)} />
          <div className="relative w-full max-w-md bg-white h-full shadow-2xl p-8 animate-in slide-in-from-right duration-500">
            <div className="flex items-center justify-between mb-10">
              <div className="flex items-center gap-3"><History size={20} /><h3 className="text-2xl font-black">Lịch sử</h3></div>
              <button onClick={() => setShowHistory(false)}><X size={24} /></button>
            </div>
            <div className="space-y-4 overflow-y-auto max-h-[calc(100vh-200px)]">
              {history.length === 0 ? (
                <p className="text-center text-slate-400 py-10">Chưa có lịch sử trích xuất.</p>
              ) : (
                history.map(item => (
                  <div key={item.id} className="p-5 bg-slate-50 rounded-3xl hover:bg-white cursor-pointer group transition-all" onClick={() => handleLoadHistory(item)}>
                    <p className="font-black text-slate-900 truncate">{item.fileName}</p>
                    <div className="flex justify-between items-center mt-2">
                      <span className="text-[10px] text-slate-400">{new Date(item.timestamp).toLocaleString()}</span>
                      <button onClick={(e) => { e.stopPropagation(); handleDeleteHistory(item.id); }} className="text-slate-300 hover:text-rose-500"><Trash2 size={16} /></button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {showNotification && (
        <div className="fixed top-10 left-1/2 -translate-x-1/2 z-[100] animate-in slide-in-from-top-10 no-print">
          <div className={`px-10 py-4 rounded-[2rem] shadow-2xl font-black text-white flex items-center gap-4 ${showNotification.type === 'success' ? 'bg-emerald-500' : 'bg-rose-500'}`}>
            {showNotification.type === 'success' ? <Check size={20} /> : <AlertCircle size={20} />}
            <span>{showNotification.message}</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import XLSX from 'xlsx';
import { ExtractedDocument, ExcelExportConfig } from '../types';

export const exportToExcel = (
  data: ExtractedDocument[], 
  fileName: string = 'ket_qua_trich_xuat',
  config: ExcelExportConfig
) => {
  const formattedData = data.map(item => ({
    "Số ký hiệu": item.symbol,
    "Ngày tháng": item.date.replace(/'/g, ''),
    "Trích yếu nội dung": `${item.docType} ${item.summary}`,
    "Cơ quan ban hành": item.authority,
    "Số trang": item.pageRange?.replace(/'/g, ''),
  }));

  const worksheet = XLSX.utils.json_to_sheet(formattedData);
  const range = XLSX.utils.decode_range(worksheet['!ref'] || "A1:A1");

  const borderStyle = config.allBorders ? {
    top: { style: "thin", color: { rgb: "000000" } },
    bottom: { style: "thin", color: { rgb: "000000" } },
    left: { style: "thin", color: { rgb: "000000" } },
    right: { style: "thin", color: { rgb: "000000" } }
  } : {};

  const fontStyle = {
    name: config.fontName,
    sz: config.fontSize,
  };

  for (let R = range.s.r; R <= range.e.r; ++R) {
    for (let C = range.s.c; C <= range.e.c; ++C) {
      const cellAddress = XLSX.utils.encode_cell({ r: R, c: C });
      if (!worksheet[cellAddress]) continue;

      const cell = worksheet[cellAddress];
      if (!cell.s) cell.s = {};

      cell.s.font = { ...fontStyle };
      if (config.allBorders) cell.s.border = borderStyle;

      cell.s.alignment = { 
        vertical: "center",
        wrapText: config.wrapText 
      };

      if (R === 0) {
        cell.s.font = { ...fontStyle, bold: true };
        cell.s.alignment = { horizontal: "center", vertical: "center", wrapText: true };
        cell.s.fill = { fgColor: { rgb: "EFEFEF" } };
      } else {
        if (C === 1 || C === 4) { 
            cell.s.alignment = { horizontal: "center", vertical: "center" };
        }
        if (C === 2) {
            cell.s.alignment = { horizontal: "left", vertical: "top", wrapText: true };
        }
      }
    }
  }

  const wscols = [
    { wch: 20 }, // Symbol
    { wch: 15 }, // Date
    { wch: 65 }, // Summary
    { wch: 35 }, // Authority
    { wch: 15 }, // Page Range
  ];
  worksheet['!cols'] = wscols;

  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Mục lục văn bản");
  XLSX.writeFile(workbook, `${fileName}.xlsx`);
};

import { GoogleGenAI, Type } from "@google/genai";
import { ExtractedDocument } from "../types";
import { PDFDocument } from "pdf-lib";

const API_LIMIT_BYTES = 30 * 1024 * 1024; 
const PAGES_PER_CHUNK = 15; 

const uint8ArrayToBase64 = (bytes: Uint8Array): string => {
  let binary = "";
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
};

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = () => reject(new Error("Lỗi khi đọc file."));
  });
};

const documentSchema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      docType: {
        type: Type.STRING,
        description: "Loại văn bản (Quyết định, Thông báo, Công văn, Kế hoạch...)",
      },
      symbol: {
        type: Type.STRING,
        description: "Số ký hiệu văn bản. Nếu không có để trống.",
      },
      date: {
        type: Type.STRING,
        description: "Ngày tháng văn bản (định dạng dd/mm/yyyy).",
      },
      summary: {
        type: Type.STRING,
        description: "Trích yếu nội dung tiếp nối sau tên loại văn bản. Giữ nguyên văn phong gốc, không đảo từ ngữ.",
      },
      authority: {
        type: Type.STRING,
        description: "Cơ quan ban hành văn bản trực tiếp.",
      },
      startPage: {
        type: Type.INTEGER,
        description: "Số trang bắt đầu (số bút chì ghi ở góc trên bên phải trang đầu của văn bản).",
      }
    },
    required: ["docType", "symbol", "date", "summary", "authority", "startPage"],
  },
};

const processChunk = async (ai: GoogleGenAI, base64Data: string): Promise<ExtractedDocument[]> => {
  const systemInstruction = `Bạn là chuyên gia văn thư lưu trữ với độ chính xác tuyệt đối. 
Nhiệm vụ: Bóc tách TOÀN BỘ các văn bản hành chính trong tệp PDF.

QUY TẮC NGHIÊM NGẶT (KHÔNG ĐƯỢC VI PHẠM):
1. KHÔNG ĐẢO VĂN BẢN: Phải liệt kê văn bản theo đúng thứ tự xuất hiện trong file PDF từ trang đầu đến trang cuối. Không được xáo trộn vị trí.
2. ĐỘ CHÍNH XÁC SỐ LƯỢNG: TUYỆT ĐỐI đảm bảo số lượng văn bản trích xuất là chính xác. Mỗi văn bản phải được xác định duy nhất bởi trang bắt đầu của nó (startPage) và các thông tin ký hiệu, ngày tháng. Không bỏ sót văn bản, không tạo văn bản trùng lặp không có thật.
3. GIỮ NGUYÊN NỘI DUNG: Trích yếu phải bám sát văn bản gốc. Không tóm tắt làm mất đi các từ ngữ chuyên môn hoặc làm thay đổi ý nghĩa gốc.
4. CƠ QUAN BAN HÀNH (authority): 
   - KHÔNG viết in hoa tất cả các chữ cái.
   - CHỈ viết hoa chữ cái đầu tiên và các từ là tên riêng (Ví dụ: 'Ủy ban nhân dân tỉnh Lâm Đồng').
5. LOẠI VĂN BẢN & TRÍCH YẾU:
   - Tách biệt rõ Loại văn bản (Quyết định, Công văn...) và Trích yếu.
   - Trích yếu bắt đầu bằng chữ thường. Nếu là văn bản nhân sự, bắt buộc có tên đối tượng thụ hưởng.
6. SỐ HIỆU: Ghi đầy đủ (Ví dụ: 123/QĐ-UBND).
7. SỐ TRANG (startPage): Ưu tiên trích xuất số ghi bằng bút chì ở góc trên bên phải trang đầu của văn bản. Đây là yếu tố then chốt để phân biệt các văn bản. Nếu không thấy, hãy ước lượng dựa trên số thứ tự trang PDF thực tế.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            { inlineData: { mimeType: "application/pdf", data: base64Data } },
            { text: "Hãy trích xuất danh sách văn bản theo đúng thứ tự xuất hiện, tuyệt đối không đảo văn bản và đảm bảo độ chính xác số lượng." }
          ],
        },
      ],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: documentSchema,
      },
    });

    const result = response.text;
    if (!result) return [];

    const cleanJson = result.replace(/```json/g, '').replace(/```/g, '').trim();
    const rawData: ExtractedDocument[] = JSON.parse(cleanJson);

    return rawData;
  } catch (e: any) {
    console.error("Gemini processing error:", e);
    throw e;
  }
};

export const extractDataFromPdf = async (file: File): Promise<ExtractedDocument[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const arrayBuffer = await file.arrayBuffer();
  const pdfDoc = await PDFDocument.load(arrayBuffer);
  const totalPdfPages = pdfDoc.getPageCount();

  let allResults: ExtractedDocument[] = [];

  try {
    if (file.size <= API_LIMIT_BYTES) {
      const base64Data = await fileToBase64(file);
      allResults = await processChunk(ai, base64Data);
    } else {
      for (let i = 0; i < totalPdfPages; i += PAGES_PER_CHUNK) {
        const newDoc = await PDFDocument.create();
        const end = Math.min(i + PAGES_PER_CHUNK, totalPdfPages);
        const pagesToCopy = Array.from({ length: end - i }, (_, k) => i + k);
        const copiedPages = await newDoc.copyPages(pdfDoc, pagesToCopy);
        copiedPages.forEach(page => newDoc.addPage(page));
        const pdfBytes = await newDoc.save();
        const base64Chunk = uint8ArrayToBase64(pdfBytes);
        const chunkResults = await processChunk(ai, base64Chunk);
        allResults = [...allResults, ...chunkResults];
      }
    }

    // Sort all results by startPage first to maintain physical order
    allResults.sort((a, b) => a.startPage - b.startPage);

    // Filter for truly unique documents using a comprehensive key including startPage
    const seenKeys = new Set<string>();
    const uniqueResults: ExtractedDocument[] = [];

    for (const doc of allResults) {
      // Create a unique key for each document based on its identifying properties
      const key = `${doc.startPage}-${doc.symbol || ''}-${doc.date || ''}-${doc.summary || ''}`.toLowerCase();

      if (!seenKeys.has(key)) {
        seenKeys.add(key);
        uniqueResults.push(doc);
      }
    }

    return uniqueResults.map((doc, index, array) => {
      const nextDoc = array[index + 1];
      const startPage = doc.startPage;
      let endPage: number | null = null;

      if (nextDoc) {
        endPage = nextDoc.startPage - 1;
      }

      // Format pageRange without the leading apostrophe
      let displayRange = `${startPage}`;
      if (endPage !== null && endPage > startPage) {
        displayRange = `${startPage} - ${endPage}`;
      }

      const formattedDate = doc.date ? (doc.date.startsWith("'") ? doc.date : `'${doc.date}`) : "";

      return {
        ...doc,
        date: formattedDate,
        pageRange: displayRange
      };
    });
  } catch (error: any) {
    throw new Error(error.message || "Lỗi xử lý PDF.");
  }
};

